		V_DISPLAY:='ΕΠΙΚΟΥΡΙΚΗΣ ΣΥΝΤΑΞΗΣ ΓΗΡΑΤΟΣ e-ΕΦΚΑ';
	end if;
	IF :PRODUCT_CODE='00002' THEN
		V_DISPLAY:='ΕΠΙΚΟΥΡΙΚΗΣ ΣΥΝΤΑΞΗΣ ΑΝΑΠΗΡΙΑΣ e-ΕΦΚΑ';
	end if;
	IF :PRODUCT_CODE='00003' THEN
		V_DISPLAY:='ΕΠΙΚΟΥΡΙΚΗΣ ΣΥΝΤΑΞΗΣ ΘΑΝΑΤΟΥ ΑΣΦΑΛΙΣΜΕΝΟΥ e-ΕΦΚΑ';
	end if;
	IF :PRODUCT_CODE='00004' THEN
		V_DISPLAY:='ΕΠΙΚΟΥΡΙΚΗΣ ΣΥΝΤΑΞΗΣ ΘΑΝΑΤΟΥ ΣΥΝΤΑΞΙΟΥΧΟΥ e-ΕΦΚΑ';
	end if;	
END IF;		

return v_display;
