      function MONTHS_200_TEAMFormula return Char is

V_DISPLAY    CHAR(5);
V_QUAL_SUBTERM CHAR(5);

begin
	IF :FIRST_EPILOGH_APO_ETEAM='1' THEN
		IF :P_MONTHS_200 LIKE '0%' THEN
			V_DISPLAY:='XXXXX';
		ELSE
			V_DISPLAY:=:P_MONTHS_200;
		END IF;
		
	ELSE
		--IF :FIRST_MEIOSH_SYNTAKSHS_TEAM IS NOT NULL THEN			
	 	IF :FIRST_MEIOSH_SYNTAKSHS_TEAM_2 IS NOT NULL AND :FIRST_MEIOSH_SYNTAKSHS_TEAM IS NULL THEN
	 		V_DISPLAY:=:FIRST_MEIOSH_SYNTAKSHS_TEAM_2;
	 	ELSIF :FIRST_MEIOSH_SYNTAKSHS_TEAM IS NOT NULL THEN
	 		V_DISPLAY:=:FIRST_MEIOSH_SYNTAKSHS_TEAM;
	 	END IF;	
		/*ELSE
			V_DISPLAY:=:FIRST_MEIOSH_TEAM_200;*/
	--	END IF;
	END IF;
	
	SELECT PEN_ACCOUNT.QUALIFYING_SUBTERM_CODE
	INTO V_QUAL_SUBTERM
	FROM PEN_ACCOUNT
	WHERE PEN_ACCOUNT.ACCOUNT_NO=:P_ACC_ACCOUNT_NO;
	
	IF V_QUAL_SUBTERM IN (650,657) THEN
		V_DISPLAY:=' ';
	END IF;
	
	RETURN V_DISPLAY;
	
