			 :DEDUCTION_EXCEPTION != 1 THEN
			V_DISPLAY:='ΜΕΙΩΜΕΝΗ';
		ELSIF (:FIRST_MEIOSH_SYNTAKSHS_TEAM IS NULL AND :FIRST_MEIOSH_TEAM_200 IS NOT NULL AND :FIRST_MEIOSH_TEAM_200!='0' ) AND 
			     :DEDUCTION_EXCEPTION != 1 THEN
