		END IF;
	END IF;
	
	IF :QUALIFYING_SUBTERM_CODE2 IN ('650','657') THEN
		V_DISPLAY:='ΠΛΗΡΗ';
	END IF;
	:CP_1	:=V_DISPLAY;
	RETURN V_DISPLAY;
end;

