      function CF_267Formula return Char is
 
 V_START_DATE_MAIN_V	VARCHAR2(10);
 V_START_DATE_MAIN		DATE;

CURSOR CUR_VALUE4 IS
	SELECT value 
	FROM pen_dec_fact_types_instance
	WHERE pen_dec_fact_types_instance.title_code IN ('00070', '00071') AND 
	pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
	pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
	pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
	pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
	pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND 
	pen_dec_fact_types_instance.dec_fact_type_code = '00114';

	----17/12/2008----------------
	v_denominator		 NUMBER;
	CURSOR cur_age_reduction_denom IS
	SELECT denominator
	FROM PEN_AGE_REDUCTION_DENOM
	WHERE VALIDITY_DATE <= V_START_DATE_MAIN --:P_FACTITIOUS_DATE
	ORDER BY VALIDITY_DATE DESC;
	-------------------------------

BEGIN
	
/*  IF :P_FACTITIOUS_DATE >= '1/1/2003' THEN 
  	RETURN ('/267');
  ELSE 
  	RETURN ('/200');
  END IF; */	
  
IF NVL(:P_ACC_ACCOUNT_NO2,0) > 0 THEN
  BEGIN
	  SELECT PEN_ACCOUNT.START_DATE
	  INTO V_START_DATE_MAIN
		FROM PEN_ACCOUNT
		WHERE PEN_ACCOUNT.ACCOUNT_NO=:P_ACC_ACCOUNT_NO2;
  
  -- insert into error_debug values (:p_insured_id,'1-V_START_DATE_MAIN',V_START_DATE_MAIN);commit;
  EXCEPTION
  	WHEN OTHERS THEN
  	NULL;
  END;
ELSE
	OPEN CUR_VALUE4;
	FETCH CUR_VALUE4
	INTO V_START_DATE_MAIN_V;
	CLOSE CUR_VALUE4;
	IF V_START_DATE_MAIN_V IS NOT NULL THEN
	--	insert into error_debug values (:p_insured_id,'2-V_START_DATE_MAIN',V_START_DATE_MAIN);commit;
		V_START_DATE_MAIN := TO_DATE(V_START_DATE_MAIN_V,'DD/MM/RRRR');
	END IF;
END IF;
 
-- insert into error_debug values (:p_insured_id,'V_START_DATE_MAIN',V_START_DATE_MAIN);commit;
  
  
	----17/12/2008---
	OPEN cur_age_reduction_denom;
	FETCH cur_age_reduction_denom
	INTO v_denominator;
	CLOSE cur_age_reduction_denom;
				
	RETURN ('/'||v_denominator);				
	-----------------			
	
end;

