      function CF_12Formula return Char is
V_PROMPT     VARCHAR2(500);

Cursor cur_award_prompt Is
 SELECT A.EXTRA_ANNOUNCE_INS
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DOCUMENT_TYPE_DEC_CODE_SR ='1'  AND 
	A.INCR_SEQ_NO_SR =   :P_DEC_INCR_SEC_NO_SR AND 
	A.DECISION_YEAR_SR=  :p_dt_decision_year AND 
	A.DEC_UNIT_CODE_SR = :p_dt_dec_unit_code;

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_PROMPT;
 CLOSE cur_award_prompt;
 
 
 RETURN V_PROMPT;
 
end;

      function CF_12FORMULA0019 return Char is

V_PROMPT     VARCHAR2(500);

Cursor cur_award_prompt Is
 SELECT A.EXTRA_ANNOUNCE_PAY_BRANCH
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DOCUMENT_TYPE_DEC_CODE_SR ='1'  AND 
	A.INCR_SEQ_NO_SR =   :P_DEC_INCR_SEC_NO_SR AND 
	A.DECISION_YEAR_SR=  :p_dt_decision_year AND 
	A.DEC_UNIT_CODE_SR = :p_dt_dec_unit_code;

begin
 
