	  if :CP_DOC_TROP_CODE = '006' then   ---- ΤΡΟΠΟΠΟΙΗΣΗ ΣΥΝΤΑΞΗΣ  ---SPAP 08/12/2020 DUE TO MAIL BY EMETAXA & EKAMPA TELEPHONE
	   to_return := 'ΤΡΟΠΟΠΟΙΟΥΜΕ ΤΗΝ ΑΠΟΦΑΣΗ '||:CP_CONV_DECISION||' '||v_reason_dscr;
	  elsif :CP_DOC_TROP_CODE = '301' then   ---- ΑΝΑΘΕΩΡΗΣΗ ΣΥΝΤΑΞΗΣ
	   to_return := 'ΑΝΑΘΕΩΡΟΥΜΕ ΤΗΝ ΑΠΟΦΑΣΗ '||:CP_CONV_DECISION||' '||v_reason_dscr;
	  else --- ΜΕΤΑΤΡΟΠΗ ΣΥΝΤΑΞΗΣ 
