  FROM 		PEN_CALC_ADAPOD_RESULTS_ETEAEP A
  WHERE 	ACCOUNT_NO             = :P_ACC_ACCOUNT_NO
  AND     INSTITUTION_CODE       = PENBAT_FIND_INTROD_INSTIT_CODE(:P_ACC_ACCOUNT_NO) ---ΓΙΑ ΑΠΟΝΕΜΩΝ
  AND     YEAR                  <= 2014
  ORDER BY AGE_REDUCTION DESC;
  	
  v_res number;
  
begin
  	
    open C1;
    fetch C1 
    into V_NUMBER;
    close C1;
   	
 -- PENBAT_DEBUGING('P_ACC_ACCOUNT_NO = '||:P_ACC_ACCOUNT_NO, 'CHRYS_24012023');
 -- PENBAT_DEBUGING('V_NUMBER = '||V_NUMBER, 'CHRYS_24012023');
 -- PENBAT_DEBUGING('cs_incr_amount = '||:cs_incr_amount_a_aponemon, 'CHRYS_24012023');
 -- PENBAT_DEBUGING('cs_amount_a = '||:cs_amount_a_a_aponemon, 'CHRYS_24012023');
   
   -- CHRYS 24/1/2023 v_res := nvl(V_NUMBER,0)*(nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0))/100 ;
   v_res := nvl(V_NUMBER,0)*(nvl(:cs_amount_a_aponemon,0) + nvl(:cs_incr_amount_a_aponemon,0)) ; -- CHRYS 24/1/2023
   return v_res;
   
end;

      function cf_final_amount_a_aponemon return Number is

-- CHRYS 4/7/2022
V_AMOUNT_A	NUMBER; 

CURSOR 	CUR_AMOUNT_A IS
SELECT 	DISTINCT ADAPODOTIKH_AMT
FROM		PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE 	ACCOUNT_NO              = :P_ACC_ACCOUNT_NO
AND			NVL(ADAPODOTIKH_AMT,0) != 0
AND     INSTITUTION_CODE        = PENBAT_FIND_INTROD_INSTIT_CODE(:P_ACC_ACCOUNT_NO) ---ΓΙΑ ΑΠΟΝΕΜΩΝ
AND     YEAR                   <= 2014
;
-- END CHRYS 4/7/2022

begin

	V_AMOUNT_A := nvl(:cs_amount_a_aponemon,0) + nvl(:cs_incr_amount_a_aponemon,0) - nvl(:cf_age_reduct_a_aponemon,0)- nvl(:cf_disab_reduct_a_apon,0); -- CHRYS 4/7/2022 
	IF V_AMOUNT_A != 0 THEN
		RETURN V_AMOUNT_A;
	ELSE
		OPEN	CUR_AMOUNT_A;
		FETCH	CUR_AMOUNT_A
		INTO V_AMOUNT_A;
		CLOSE CUR_AMOUNT_A;	
   	RETURN V_AMOUNT_A;
  END IF;
end;

      function cf_amount_b_aponemon return Number 
is
  cursor c1
  is
    select distinct  
		       a.ranta,
		       a.total_contributions_amt_b contr_amount
		  from pen_calc_adapod_results_eteaep a
		 where a.account_no                        = :P_ACC_ACCOUNT_NO -- CHRYS 13/8/2018 :P_INSURED_ID
		   and nvl(a.total_contributions_amt_b,0) <> 0
		   and a.institution_code                  = penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO) ---για απονεμων
       and year                               >= 2015		   
		   ;
  
  v_contr_amount_aponemon number;
  
begin
   open c1;
   fetch c1 into :cp_b_aponemon_ranta, v_contr_amount_aponemon;
   close c1;
   
   return v_contr_amount_aponemon;
   
end;

      function cf_amount_b_b_aponemon return Number 
is

-- CHRYS 4/7/2022

CURSOR CUR_AMOUNT_B IS
SELECT DISTINCT AMOUNT_B
FROM	PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE ACCOUNT_NO         = :P_ACC_ACCOUNT_NO
AND		NVL(AMOUNT_B,0)   != 0
and   institution_code   = penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO) ---για απονεμων
and   year              >= 2015
  ;

-- END CHRYS 4/7/2022

  cursor c1
  is
    select distinct
           round(a.total_contributions_amt_b/(a.ranta * 12),2) poso_b
      from pen_calc_adapod_results_eteaep a
     where a.account_no                        = :P_ACC_ACCOUNT_NO -- CHRYS 28/8/2018 :P_INSURED_ID
       and nvl(a.total_contributions_amt_b,0) <> 0
       and a.institution_code                  = penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO) ---για απονεμων
	     and year                               >= 2015;
  
  v_amount_b number;
  
begin
   open c1;
   fetch c1 into v_amount_b;
   close c1;
   
	IF V_AMOUNT_B != 0 THEN
		RETURN V_AMOUNT_B;
	ELSE
		OPEN	CUR_AMOUNT_B;
		FETCH	CUR_AMOUNT_B
		INTO V_AMOUNT_B;
		CLOSE CUR_AMOUNT_B;	
   	RETURN V_AMOUNT_B;
  END IF;
   
end;

