      function M_87FormatTrigger return boolean is

v_calc_begin_date_varchar		varchar2(10); -- CHRYS 21/5/2019
v_calc_begin_date_varchar2	varchar2(10); -- CHRYS 21/5/2019

begin
	
	IF :P_ERGASIA_2024 = 0 THEN
			-- CHRYS 10/6/2019  
				-- ΠΡΙΝ ΤΙΣ 13/6/2016, ΣΤΟΝ ΔΗΜΟΣΙΟ ΤΟΜΕΑ
				-- 1. ΣΥΝΕΧΙΣΗ ΕΡΓΑΣΙΑΣ
				v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
				0,:p_form_id,'00001','00019','00033');
				IF v_calc_begin_date_varchar IS NULL THEN
						v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
						0,:p_form_id,'00001','00333','00033');
				END IF;
			
				-- 2. ΤΟΜΕΑΣ ΕΡΓΑΣΙΑΣ
				IF v_calc_begin_date_varchar = '1' THEN
					v_calc_begin_date_varchar2 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					0,:p_form_id,'00001','00019','00410');
					IF v_calc_begin_date_varchar2 IS NULL THEN
						v_calc_begin_date_varchar2 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
						0,:p_form_id,'00001','00333','00410');
					END IF;
				END IF;
			
				--ΑΝ ΕΙΝΑΙ ΓΗΡΑΤΟΣ, ΕΡΓΑΖΕΤΑΙ ΣΤΟ ΔΗΜΟΣΙΟ ΤΟΜΕΑ 
			 	IF 	v_calc_begin_date_varchar2 IN ('Δ') AND :CF_PRODUCT = '00001'  THEN
			 		RETURN (TRUE);
				ELSE
					RETURN FALSE;
				END IF;
			-- END CHRYS 10/6/2019  
  ELSE
		RETURN FALSE;
  END IF;
  
END;

      function CF_16Formula return Number is

CURSOR CUR_SECTOR IS
 SELECT Work_Ins_Sector  SECTOR
  FROM PEN_ACCOUNT_WORKING_INFO
  WHERE ACCOUNT_NO =  :P_ACC_ACCOUNT_NO;

v_calc_begin_date_varchar2 VARCHAR2(20);

v_num 	NUMBER;

begin

		v_calc_begin_date_varchar2 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
		0,:p_form_id,'00001','00019','00410');
		IF v_calc_begin_date_varchar2 IS NULL THEN
			v_calc_begin_date_varchar2 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			0,:p_form_id,'00001','00333','00410');
		END IF;


	IF v_calc_begin_date_varchar2 = 'Δ' AND :CF_PRODUCT = '00001'  THEN
    	v_num := NVL(:cf_amount_ab_b_aponemon,0) *0.7;
	ELSE
			v_num := 0;
	END IF;
	
  return (v_num);
end;

