      function CF_46Formula return Date is

V_NUM DATE;


CURSOR CUR_1 IS
SELECT FROM_WORKING_DATE
FROM PEN_OPS.PEN_PREPARE_DAYS , 
COM_INSURANCE_HISTORY_TYPES,
COM_COVERS_PER_COVERAGES
WHERE PEN_OPS.PEN_PREPARE_DAYS.INS_INSURED_ID=:P_INSURED_ID 
AND PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE=COM_INSURANCE_HISTORY_TYPES.TRANS_TYPE
and COM_COVERS_PER_COVERAGES.COVCOD_COVERAGE_CODE=PEN_PREPARE_DAYS.COVCOD_COVERAGE_CODE
and COM_COVERS_PER_COVERAGES.CVR_COVER_CODE='ΚΣΙ'
AND PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE IN ('810','820','830','840');
--GROUP BY FROM_WORKING_DATE;

BEGIN
	
	OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM;      
  CLOSE CUR_1;
  
  RETURN V_NUM;
  
  
  EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
END;

      function CF_47Formula return Date is

V_NUM DATE;

CURSOR CUR_1 IS
SELECT TO_WORKING_DATE
FROM PEN_OPS.PEN_PREPARE_DAYS , 
COM_INSURANCE_HISTORY_TYPES,
COM_COVERS_PER_COVERAGES
WHERE PEN_OPS.PEN_PREPARE_DAYS.INS_INSURED_ID=:P_INSURED_ID 
AND PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE=COM_INSURANCE_HISTORY_TYPES.TRANS_TYPE
and COM_COVERS_PER_COVERAGES.COVCOD_COVERAGE_CODE=PEN_PREPARE_DAYS.COVCOD_COVERAGE_CODE
and COM_COVERS_PER_COVERAGES.CVR_COVER_CODE='ΚΣΙ'
AND PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE IN ('810','820','830','840');
--GROUP BY TO_WORKING_DATE;

BEGIN
	
	OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM;
  CLOSE CUR_1;
  
  RETURN V_NUM;
  
  
  EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
	
END;

