      function cf_final_amount_a_other return Number is

-- CHRYS 4/7/2022
V_AMOUNT_A	NUMBER; 

/* 
CURSOR 	CUR_AMOUNT_A IS
SELECT 	DISTINCT ADAPODOTIKH_AMT
FROM		PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE 	ACCOUNT_NO              = :P_ACC_ACCOUNT_NO
AND			NVL(ADAPODOTIKH_AMT,0) != 0
AND     INSTITUTION_CODE       != PENBAT_FIND_INTROD_INSTIT_CODE(:P_ACC_ACCOUNT_NO) ---ΓΙΑ ΑΛΛΟΥΣ ΦΟΡΕΙΣ
AND     YEAR                  <= 2014
AND     NVL(MULTIPLE_FLG,'0')  = '1'
;
-- END CHRYS 4/7/2022
*/

CURSOR 	CUR_AMOUNT_A IS
SELECT 	SUM(DISTINCT NVL(ADAPODOTIKH_AMT_PER_ADD,0))
FROM		PEN_CALC_0075_RES_ETEAEP_DA
WHERE 	ACCOUNT_NO              = :P_ACC_ACCOUNT_NO
--AND     INSTITUTION_CODE       != PENBAT_FIND_INTROD_INSTIT_CODE(:P_ACC_ACCOUNT_NO) ---ΓΙΑ ΑΛΛΟΥΣ ΦΟΡΕΙΣ
AND     YEAR                  <= 2014
--AND     NVL(MULTIPLE_FLG,'0')  = '1'
;

begin
	
	V_AMOUNT_A := nvl(:cs_amount_a_other,0) + nvl(:cs_incr_amount_a_other,0) - nvl(:cf_age_reduct_a_other,0)- nvl(:cf_disab_reduct_a_other,0); -- CHRYS 4/7/2022 
	--IF V_AMOUNT_A != 0 THEN
		-- RETURN V_AMOUNT_A;
	--	NULL;
	--ELSE
		OPEN	CUR_AMOUNT_A;
		FETCH	CUR_AMOUNT_A
		INTO V_AMOUNT_A;
		CLOSE CUR_AMOUNT_A;	
   	RETURN V_AMOUNT_A;
 -- END IF;
end;

      function cf_age_reduct_a_other return Number 
is
-- CHRYS 24/1/2023
V_NUMBER		NUMBER;
  
  CURSOR 	C1 IS
  SELECT 	DISTINCT AGE_REDUCTION
  FROM 		PEN_CALC_ADAPOD_RESULTS_ETEAEP A
  WHERE 	ACCOUNT_NO             = :P_ACC_ACCOUNT_NO
  AND     INSTITUTION_CODE      != PENBAT_FIND_INTROD_INSTIT_CODE(:P_ACC_ACCOUNT_NO) ---ΓΙΑ ΑΠΟΝΕΜΩΝ
  AND     YEAR                  <= 2014
  AND     NVL(MULTIPLE_FLG,'0')  = '1'
  ORDER BY AGE_REDUCTION DESC;
  	
  v_res number;
  
begin
  	
    open C1;
    fetch C1 
    into V_NUMBER;
    close C1;
   	
 -- PENBAT_DEBUGING('P_ACC_ACCOUNT_NO = '||:P_ACC_ACCOUNT_NO, 'CHRYS_24012023');
 -- PENBAT_DEBUGING('V_NUMBER = '||V_NUMBER, 'CHRYS_24012023');
 -- PENBAT_DEBUGING('cs_incr_amount = '||:cs_incr_amount_a_aponemon, 'CHRYS_24012023');
 -- PENBAT_DEBUGING('cs_amount_a = '||:cs_amount_a_a_aponemon, 'CHRYS_24012023');
   
   -- CHRYS 24/1/2023 v_res := nvl(V_NUMBER,0)*(nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0))/100 ;
   v_res := nvl(V_NUMBER,0)*(nvl(:cs_amount_a_other,0) + nvl(:cs_incr_amount_a_other,0)) ; -- CHRYS 24/1/2023
   return v_res;
   
end;

      function CF_DISAB_REDUCT_A_OTHER return Number is

V_NUMBER			NUMBER;
V_REDUCTION		NUMBER;

v_calc_begin_date_varchar varchar2(10);

begin
	
  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',0,:p_form_id,'00001','00035','00200');
  
  IF v_calc_begin_date_varchar IS NOT NULL THEN
     v_NUMBER := 100-TO_NUMBER(v_calc_begin_date_varchar);
  END IF;

  v_reduction := nvl(V_NUMBER,0)*(nvl(:cs_amount_a_other,0) + nvl(:cs_incr_amount_a_other,0))/100 ;

  RETURN V_REDUCTION;

end;

