FROM   pen_calc_adapod_results_eteaep A
WHERE a.ACCOUNT_NO             = :P_ACC_ACCOUNT_NO
and   nvl(a.v_percent_ksb,0)   = 0
and   nvl(a.average_income,0) <> 0
and   year                    <= 2014
and   institution_code        != penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO)
and   nvl(multiple_flg,'0')    = '1'
;

V_MAX_DATE DATE;
begin
  
  OPEN CUR_MAX_DATE;
  FETCH CUR_MAX_DATE
  INTO V_MAX_DATE;
  CLOSE CUR_MAX_DATE;
  
  RETURN V_MAX_DATE;
  
end;

