      function cf_amount_b_other return Number 
is
  cursor c1
  is
    select distinct
		       a.ranta,
		       a.total_contributions_amt_b contr_amount
		  from pen_calc_adapod_results_eteaep a
		 where a.account_no                        = :P_ACC_ACCOUNT_NO -- CHRYS 13/8/2018 :P_INSURED_ID
		   and nvl(a.total_contributions_amt_b,0) <> 0
		   and year                               >= 2015
			 and institution_code                   != penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO) ---για μη απονεμoντες φορεις   
			 and institution_code                    = :INST_B_OTHER_CODE
		   ;
  
  v_contr_amount_other number;
  
begin
   open c1;
   fetch c1 into :cp_b_other_ranta, v_contr_amount_other;
   close c1;
   
   return v_contr_amount_other;
   
end;

      function cf_amount_b_b_other return Number 
is

-- CHRYS 4/7/2022

CURSOR CUR_AMOUNT_B IS
SELECT DISTINCT AMOUNT_B
FROM	PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE ACCOUNT_NO         = :P_ACC_ACCOUNT_NO
AND		NVL(AMOUNT_B,0)   != 0
and   institution_code  != penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO) 
and   year              >= 2015
and   institution_code   = :INST_B_OTHER_CODE
  ;

-- END CHRYS 4/7/2022

  cursor c1
  is
    select distinct
           round(a.total_contributions_amt_b/(a.ranta * 12),2) poso_b
      from pen_calc_adapod_results_eteaep a
     where a.account_no                        = :P_ACC_ACCOUNT_NO -- CHRYS 28/8/2018 :P_INSURED_ID
       and nvl(a.total_contributions_amt_b,0) <> 0
       and a.institution_code                 != penbat_find_introd_instit_code(:P_ACC_ACCOUNT_NO) 
	     and year                               >= 2015
	     and institution_code                    = :INST_B_OTHER_CODE
	     ;
  
  v_amount_b number;
  
begin
   open c1;
   fetch c1 into v_amount_b;
   close c1;
   
	IF V_AMOUNT_B != 0 THEN
		RETURN V_AMOUNT_B;
	ELSE
		OPEN	CUR_AMOUNT_B;
		FETCH	CUR_AMOUNT_B
		INTO V_AMOUNT_B;
		CLOSE CUR_AMOUNT_B;	
   	RETURN V_AMOUNT_B;
  END IF;
   
end;

      function CF_POSO_SYMMETOXHS_B_OTHER return Number is

CURSOR CUR_CONTR_AMOUNT IS
SELECT SUM(NOTICE_SALARY)
FROM  PEN_INSURED_DAYS
WHERE ACC_ACCOUNT_NO     =:P_ACC_ACCOUNT_NO
AND   DAYS_OR_AMOUNT_FLG = '2';

p_ETEAEP_CONTR		NUMBER;

-- CHRYS 4/7/2022
V_AMOUNT_SYMM	NUMBER; 

CURSOR CUR_AMOUNT_SYMM IS
SELECT AMOUNT
FROM  	PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE 	ACC_ACCOUNT_NO                = :P_ACC_ACCOUNT_NO
AND			CC_PER_BE_TYPE_PER_DECINS_UPD = '1'
AND			STATUS                        = '1'
AND			CP_CALCULATION_PARAMETER_CODE = 'ETCOA';
-- END CHRYS 4/7/2022

BEGIN

OPEN CUR_CONTR_AMOUNT;
FETCH CUR_CONTR_AMOUNT
INTO p_ETEAEP_CONTR;
CLOSE CUR_CONTR_AMOUNT;

p_ETEAEP_CONTR:= ROUND(NVL(p_ETEAEP_CONTR,0),2);

/* CHRYS 30/5/2023 
IF p_ETEAEP_CONTR != 0 THEN 
	RETURN p_ETEAEP_CONTR;
ELSE
END CHRYS 30/5/2023 */
		OPEN	CUR_AMOUNT_SYMM;
		FETCH	CUR_AMOUNT_SYMM
		INTO V_AMOUNT_SYMM;
		CLOSE CUR_AMOUNT_SYMM;	
   	RETURN V_AMOUNT_SYMM;
--CHRYS 30/5/2023  END IF;

END;

